import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api/axios';

export default function Login() {
  const { login } = useAuth();
  const navigate  = useNavigate();
  const [form, setForm]       = useState({ email: '', password: '' });
  const [error, setError]     = useState('');
  const [loading, setLoading] = useState(false);

  const handle = e => setForm({ ...form, [e.target.name]: e.target.value });

  const submit = async e => {
    e.preventDefault();
    setLoading(true);
    try {
      const { data } = await api.post('/api/auth/login', form);
      login(data);
      navigate('/dashboard');
    } catch {
      setError('Invalid email or password');
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#f4f5f7] dark:bg-gh-canvas p-4">
      <div className="w-full max-w-sm bg-white dark:bg-gh-default rounded-2xl shadow-sm dark:shadow-none dark:border dark:border-gh-border p-8">
        {/* Logo */}
        <div className="flex flex-col items-center mb-7">
          <div className="w-10 h-10 rounded-xl bg-brand-blue flex items-center justify-center mb-3">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M22 12h-4l-3 9L9 3l-3 9H2"/>
            </svg>
          </div>
          <h1 className="text-xl font-bold text-gray-900 dark:text-gh-text">Sign in to AvailAPI</h1>
          <p className="text-sm text-gray-500 dark:text-gh-muted mt-1">Your monitoring dashboard</p>
        </div>

        {error && (
          <div className="mb-4 flex items-center gap-2 px-3 py-2.5 bg-red-50 dark:bg-transparent text-red-600 dark:text-red-400 border border-red-200 dark:border-red-400/30 rounded-xl text-sm">
            <span>⚠</span> {error}
          </div>
        )}

        <form onSubmit={submit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gh-muted mb-1.5">Email address</label>
            <input
              name="email" type="email" onChange={handle} required
              placeholder="you@company.com"
              className="w-full px-3.5 py-2.5 text-sm rounded-xl bg-[#e5e7eb] dark:bg-gh-canvas border border-transparent focus:border-brand-blue focus:outline-none focus:ring-2 focus:ring-brand-blue/20 text-gray-800 dark:text-gh-text placeholder-gray-400 dark:placeholder-gh-dim transition-all"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gh-muted mb-1.5">Password</label>
            <input
              name="password" type="password" onChange={handle} required
              placeholder="••••••••"
              className="w-full px-3.5 py-2.5 text-sm rounded-xl bg-[#e5e7eb] dark:bg-gh-canvas border border-transparent focus:border-brand-blue focus:outline-none focus:ring-2 focus:ring-brand-blue/20 text-gray-800 dark:text-gh-text placeholder-gray-400 dark:placeholder-gh-dim transition-all"
            />
          </div>
          <button
            type="submit" disabled={loading}
            className="w-full py-2.5 rounded-xl text-sm font-semibold text-white bg-brand-blue hover:bg-brand-blue-h dark:bg-gh-green dark:hover:bg-gh-green-h transition-colors flex items-center justify-center gap-2 mt-1"
          >
            {loading
              ? <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full" style={{ animation: 'spin 0.6s linear infinite' }} />
              : 'Sign in'}
          </button>
        </form>

        <p className="mt-5 text-center text-sm text-gray-500 dark:text-gh-muted border-t border-gray-100 dark:border-gh-border pt-5">
          New here?{' '}
          <Link to="/register" className="text-brand-blue dark:text-brand-blue font-medium hover:underline">Create an account</Link>
        </p>
      </div>
    </div>
  );
}
